mapper.select:
SELECT projection_key, projection_type, last_version, update_time
FROM class2_counter_projection_state
WHERE projection_key = #{projectionKey}

mapper.update:
UPDATE class2_counter_projection_state
SET projection_type = #{projectionType},
    last_version = #{lastVersion},
    update_time = #{updateTime}
WHERE projection_key = #{projectionKey}
